+/**
+ * Invoke `fn` until it resolves or it has rejected `n + 1` times.
+ *
+ * `n` is the number of retries after the initial attempt.
+ */
+export function retryN<T, E>(n: number, fn: () => Task<T, E>): Task<T, E> {
+  const retries = Math.max(0, Math.floor(n));
+  return new Task((resolve, reject) => {
+    let remaining = retries;
+    const attempt = () => {
+      let current: Task<T, E>;
+      try {
+        current = fn();
+      } catch (error) {
+        reject(error as E);
+        return;
+      }
+      current.then((settled) => {
+        if (settled.isOk) {
+          resolve(settled.value);
+        } else if (remaining-- > 0) {
+          attempt();
+        } else {
+          reject(settled.error);
+        }
+      });
+    };
+    attempt();
+  });
+}
